    @Query("""
        SELECT f FROM FollowEntity f
        JOIN FETCH f.following u
        WHERE f.followerId = :userId
        ORDER BY f.createdAt DESC
    """)
    fun findFollowingsWithUser(
        @Param("userId") userId: String,
        pageable: Pageable,
    ): List<FollowEntity>

    // Projection: 필요한 컬럼만 조회
    @Query("""
        SELECT NEW com.maum.backend.repository.follow.FollowingProjection(
            f.followingId,
            f.createdAt
        )
        FROM FollowEntity f
        WHERE f.followerId = :userId
        ORDER BY f.createdAt DESC
    """)
    fun findFollowingIdsByFollowerId(
        @Param("userId") userId: String,
        pageable: Pageable,
    ): List<FollowingProjection>
}

data class FollowingProjection(
