#### 개선 3: gRPC 서비스 내 배치 조회 + Kotlin Coroutines 병렬 처리

**After - FollowGrpcService**

```kotlin
// follow-module/src/main/kotlin/com/maum/backend/controller/follow/FollowGrpcService.kt
@GrpcService
class FollowGrpcService(
    private val followService: FollowService,
) : FollowServiceGrpc.FollowServiceImplBase() {

    override fun listFollowings(
        request: ListFollowingsRequest,
        responseObserver: StreamObserver<ListFollowingsResponse>,
    ) {
        // 1. 팔로잉 ID 목록 한 번에 조회 (쿼리 1회)
        val followingIds = followService.getFollowingIds(
            userId = request.userId,
            limit = request.limit,
            offset = request.offset,
        )

        // 2. 배치 조회로 유저 정보 한 번에 가져오기 (쿼리 1회)
        val userInfoMap = userGrpcStub.batchGetUsers(
            BatchGetUsersRequest.newBuilder()
                .addAllUserIds(followingIds)
                .build()
        ).usersMap  // Map<userId, UserInfo>

        // 3. 응답 조합
        val followings = followingIds.map { followingId ->
            userInfoMap[followingId]?.toFollowingProto()
                ?: FollowingProto.getDefaultInstance()
        }

        val response = ListFollowingsResponse.newBuilder()
            .addAllFollowings(followings)
            .build()

        responseObserver.onNext(response)
        responseObserver.onCompleted()
    }
}
```

